import { useEffect, useRef } from 'react';
import { InteractionManager } from 'react-native';
import type { KangurAuthTransitionInput } from '@kangur/platform';
import type { KangurMobileDeveloperConfig } from '../config/mobileDeveloperConfig.shared';
import { scheduleInitialAuthRefreshFrame } from './authBootHelpers';

const AUTH_INITIAL_BACKGROUND_REFRESH_FALLBACK_TIMEOUT_MS = 220;

export function useAuthBootEffect({
  shouldBlockInitialSessionRefresh,
  setIsLoadingAuth,
  refreshSession,
}: {
  shouldBlockInitialSessionRefresh: boolean;
  setIsLoadingAuth: (isLoading: boolean) => void;
  refreshSession: (options: { blockUI: boolean }) => Promise<void>;
}): void {
  useEffect(() => {
    if (shouldBlockInitialSessionRefresh) {
      setIsLoadingAuth(true);
      refreshSession({
        blockUI: true,
      });
      return;
    }

    let isDisposed = false;
    let hasScheduledRefresh = false;
    let fallbackTimeoutId: ReturnType<typeof setTimeout> | null = null;
    let cancelFrame = () => {};

    const clearFallbackTimeout = (): void => {
      if (fallbackTimeoutId !== null) {
        clearTimeout(fallbackTimeoutId);
        fallbackTimeoutId = null;
      }
    };

    const scheduleRefresh = (): void => {
      if (isDisposed || hasScheduledRefresh) {
        return;
      }

      hasScheduledRefresh = true;
      clearFallbackTimeout();
      cancelFrame = scheduleInitialAuthRefreshFrame(() => {
        if (isDisposed) {
          return;
        }

        refreshSession({
          blockUI: false,
        });
      });
    };

    const interactionTask = InteractionManager.runAfterInteractions(
      scheduleRefresh,
    );
    fallbackTimeoutId = setTimeout(
      scheduleRefresh,
      AUTH_INITIAL_BACKGROUND_REFRESH_FALLBACK_TIMEOUT_MS,
    );

    return () => {
      isDisposed = true;
      clearFallbackTimeout();
      interactionTask.cancel();
      cancelFrame();
    };
  }, [shouldBlockInitialSessionRefresh, setIsLoadingAuth, refreshSession]);
}

export function useDeveloperAutoSignIn({
  developerAutoSignInEnabled,
  isLoadingAuth,
  isAuthenticated,
  developerConfig,
  signInWithLearnerCredentials,
}: {
  developerAutoSignInEnabled: boolean;
  isLoadingAuth: boolean;
  isAuthenticated: boolean;
  developerConfig: KangurMobileDeveloperConfig;
  signInWithLearnerCredentials: (loginName: string, password: string) => Promise<void>;
}): { hasAttemptedDeveloperAutoSignIn: boolean } {
  const hasAttemptedDeveloperAutoSignInRef = useRef(false);

  useEffect(() => {
    if (
      !developerAutoSignInEnabled ||
      isLoadingAuth ||
      isAuthenticated ||
      hasAttemptedDeveloperAutoSignInRef.current
    ) {
      return;
    }

    const { learnerLoginName, learnerPassword } = developerConfig;
    if (learnerLoginName !== null && learnerPassword !== null) {
      hasAttemptedDeveloperAutoSignInRef.current = true;
      signInWithLearnerCredentials(
        learnerLoginName,
        learnerPassword,
      );
    }
  }, [
    developerAutoSignInEnabled,
    developerConfig,
    isLoadingAuth,
    isAuthenticated,
    signInWithLearnerCredentials,
  ]);

  return { hasAttemptedDeveloperAutoSignIn: hasAttemptedDeveloperAutoSignInRef.current };
}

import type { KangurAuthAdapter, KangurAuthSession, KangurAuthTransitionInput } from '@kangur/platform';
import type { QueryClient } from '@tanstack/react-query';
import { useState, useRef, useEffect } from 'react';
import { hasKangurMobileAuthSessionPayloadChanged } from './hasKangurMobileAuthSessionPayloadChanged';
import { hasKangurMobileAuthQueryIdentityChanged } from './hasKangurMobileAuthQueryIdentityChanged';
import { invalidateKangurMobileAuthQueries } from './invalidateKangurMobileAuthQueries';
import { toAuthErrorMessage } from './authErrorHelpers';
import type { KangurMobileLocale } from '../i18n/kangurMobileI18n';

type UseKangurMobileAuthActionsOptions = {
  authAdapter: KangurAuthAdapter;
  initialSession: KangurAuthSession;
  locale: KangurMobileLocale;
  queryClient: QueryClient;
  setAuthError: (error: string | null) => void;
};

export const useKangurMobileAuthActions = ({
  authAdapter,
  initialSession,
  locale,
  queryClient,
  setAuthError,
}: UseKangurMobileAuthActionsOptions) => {
  const [session, setSession] = useState<KangurAuthSession>(initialSession);
  const sessionRef = useRef(session);
  const [isLoadingAuth, setIsLoadingAuth] = useState(false);

  useEffect(() => {
    sessionRef.current = session;
  }, [session]);

  const applyResolvedSession = async (
    nextSession: KangurAuthSession,
  ): Promise<void> => {
    const previousSession = sessionRef.current;
    if (
      hasKangurMobileAuthSessionPayloadChanged(previousSession, nextSession)
    ) {
      sessionRef.current = nextSession;
      setSession(nextSession);
    }

    if (
      hasKangurMobileAuthQueryIdentityChanged(previousSession, nextSession)
    ) {
      await invalidateKangurMobileAuthQueries(queryClient);
    }
  };

  const refreshSession = async (
    options: {
      blockUI?: boolean;
    } = {},
  ): Promise<void> => {
    const shouldBlockUI = options.blockUI !== false;
    if (shouldBlockUI) {
      setIsLoadingAuth(true);
    }

    try {
      setAuthError(null);
      const nextSession = await authAdapter.getSession();
      await applyResolvedSession(nextSession);
    } catch (error) {
      setAuthError(toAuthErrorMessage(error, locale));
    } finally {
      if (shouldBlockUI) {
        setIsLoadingAuth(false);
      }
    }
  };

  const signIn = async (input?: KangurAuthTransitionInput): Promise<void> => {
    setIsLoadingAuth(true);
    try {
      setAuthError(null);
      const nextSession = await authAdapter.signIn(input);
      await applyResolvedSession(nextSession);
    } catch (error) {
      setAuthError(toAuthErrorMessage(error, locale));
    } finally {
      setIsLoadingAuth(false);
    }
  };

  const signOut = async (): Promise<void> => {
    setIsLoadingAuth(true);
    try {
      setAuthError(null);
      const nextSession = await authAdapter.signOut();
      await applyResolvedSession(nextSession);
    } catch (error) {
      setAuthError(toAuthErrorMessage(error, locale));
    } finally {
      setIsLoadingAuth(false);
    }
  };

  const signInWithLearnerCredentials = async (
    loginName: string,
    password: string,
  ): Promise<void> =>
    signIn({
      learnerCredentials: {
        loginName,
        password,
      },
    });

  return {
    isLoadingAuth,
    refreshSession,
    session,
    setIsLoadingAuth,
    signIn,
    signInWithLearnerCredentials,
    signOut,
  };
};

import { useMemo } from 'react';

import { useKangurMobileAuth } from '../auth/KangurMobileAuthContext';
import { resolveKangurMobileScoreScope } from '../profile/mobileScoreScope';
import { useKangurMobileRuntime } from '../providers/KangurRuntimeContext';
import { resolvePersistedKangurMobileRecentResults } from '../scores/persistedKangurMobileRecentResults';
import { resolvePersistedKangurMobileTrainingFocus } from '../scores/persistedKangurMobileTrainingFocus';

const APP_STARTUP_RECENT_RESULTS_LIMIT = 3;

export type KangurAppStartupState = {
  bootError: string | null;
  hasCachedStartupData: boolean;
  isAuthResolved: boolean;
  isBootLoading: boolean;
};

type UseKangurAppStartupOptions = {
  includeCachedStartupData?: boolean;
};

export const useKangurAppStartup = (
  options: UseKangurAppStartupOptions = {},
): KangurAppStartupState => {
  const { authError, isLoadingAuth, session } = useKangurMobileAuth();
  const { storage } = useKangurMobileRuntime();
  const includeCachedStartupData = options.includeCachedStartupData ?? false;
  const scoreScopeIdentityKey =
    resolveKangurMobileScoreScope(session.user)?.identityKey ?? null;
  const cachedRecentResults = useMemo(
    () =>
      includeCachedStartupData && scoreScopeIdentityKey
        ? resolvePersistedKangurMobileRecentResults({
            identityKey: scoreScopeIdentityKey,
            limit: APP_STARTUP_RECENT_RESULTS_LIMIT,
            storage,
          })
        : null,
    [includeCachedStartupData, scoreScopeIdentityKey, storage],
  );
  const cachedTrainingFocus = useMemo(
    () =>
      includeCachedStartupData && scoreScopeIdentityKey
        ? resolvePersistedKangurMobileTrainingFocus({
            identityKey: scoreScopeIdentityKey,
            storage,
          })
        : null,
    [includeCachedStartupData, scoreScopeIdentityKey, storage],
  );
  // Keep the main loader only for the blocking session-restore path.
  const isBootLoading = isLoadingAuth && session.status !== 'authenticated';

  return {
    bootError: authError,
    hasCachedStartupData: Boolean(
      cachedRecentResults?.length ||
        cachedTrainingFocus?.strongestOperation ||
        cachedTrainingFocus?.weakestOperation,
    ),
    isAuthResolved: !isBootLoading,
    isBootLoading,
  };
};

import { startTransition, useEffect, useState } from 'react';
import { InteractionManager } from 'react-native';

import { useKangurAppBootstrap } from './KangurAppBootstrapContext';

const scheduleRouteBootFrame = (callback: () => void): (() => void) => {
  if (typeof requestAnimationFrame === 'function') {
    const frameId = requestAnimationFrame(() => {
      callback();
    });

    return () => {
      if (typeof cancelAnimationFrame === 'function') {
        cancelAnimationFrame(frameId);
      }
    };
  }

  const timeoutId = setTimeout(callback, 16);
  return () => {
    clearTimeout(timeoutId);
  };
};

export const useKangurRouteBootState = ({
  bootKey,
  fallbackTimeoutMs,
}: {
  bootKey: string;
  fallbackTimeoutMs: number;
}): boolean => {
  const { consumeInitialRouteBootstrapBypass } = useKangurAppBootstrap();
  const [shouldBypassInitialRouteBootShell] = useState(() =>
    consumeInitialRouteBootstrapBypass(),
  );
  const [isPreparingRouteView, setIsPreparingRouteView] = useState(
    () => !shouldBypassInitialRouteBootShell,
  );

  useEffect(() => {
    if (shouldBypassInitialRouteBootShell) {
      return;
    }

    setIsPreparingRouteView(true);

    let isDisposed = false;
    let hasScheduledSettle = false;
    let fallbackTimeoutId: ReturnType<typeof setTimeout> | null = null;
    let cancelFrame = () => {};

    const clearFallbackTimeout = (): void => {
      if (fallbackTimeoutId === null) {
        return;
      }

      clearTimeout(fallbackTimeoutId);
      fallbackTimeoutId = null;
    };

    const settlePreparingState = (): void => {
      if (isDisposed) {
        return;
      }

      clearFallbackTimeout();
      startTransition(() => {
        setIsPreparingRouteView(false);
      });
    };

    const scheduleSettle = (): void => {
      if (isDisposed || hasScheduledSettle) {
        return;
      }

      hasScheduledSettle = true;
      clearFallbackTimeout();
      cancelFrame = scheduleRouteBootFrame(settlePreparingState);
    };

    const interactionTask = InteractionManager.runAfterInteractions(
      scheduleSettle,
    );

    fallbackTimeoutId = setTimeout(scheduleSettle, fallbackTimeoutMs);

    return () => {
      isDisposed = true;
      clearFallbackTimeout();
      interactionTask.cancel?.();
      cancelFrame();
    };
  }, [bootKey, fallbackTimeoutMs, shouldBypassInitialRouteBootShell]);

  return isPreparingRouteView;
};

import { Text, View } from 'react-native';
import type { KangurMobileLocale } from '../i18n/kangurMobileI18n';
import {
  BASE_TONE,
  INDIGO_TONE,
  OutlineLink,
  PrimaryButton,
  SectionCard,
  StatusPill,
  SUCCESS_TONE,
  WARNING_TONE,
} from './competition-primitives';
import {
  formatCompetitionModeDescription,
  formatCompetitionModeTitle,
  formatCompetitionTierLabel,
  formatModeToken,
  formatQuestionCount,
} from './competition-utils';
import type { KangurMobileCompetitionMode } from './useKangurMobileCompetition';

type CompetitionHeaderSectionProps = {
  copy: (dict: { de: string; en: string; pl: string }) => string;
  modesCount: number;
  questionCount: number;
  routes: {
    tests: string;
    results: string;
    plan: string;
  };
};

export function CompetitionHeaderSection({
  copy,
  modesCount,
  questionCount,
  routes,
}: CompetitionHeaderSectionProps) {
  return (
    <SectionCard
      title={copy({
        de: 'Kangur-Wettbewerb',
        en: 'Kangaroo competition',
        pl: 'Konkurs Kangur',
      })}
    >
      <Text style={{ color: '#475569', fontSize: 14, lineHeight: 20 }}>
        {copy({
          de: 'Wähle eine Runde des Wettbewerbs 2024 und löse die Fragen in deinem eigenen Tempo.',
          en: 'Choose a 2024 competition round and solve the tasks at your own pace.',
          pl: 'Wybierz rundę konkursu z 2024 roku i rozwiązuj zadania we własnym tempie.',
        })}
      </Text>
      <View style={{ flexDirection: 'row', flexWrap: 'wrap', gap: 8 }}>
        <StatusPill
          label={copy({
            de: `Runden ${modesCount}`,
            en: `Rounds ${modesCount}`,
            pl: `Rundy ${modesCount}`,
          })}
          tone={INDIGO_TONE}
        />
        <StatusPill
          label={copy({
            de: `Fragen ${questionCount}`,
            en: `Questions ${questionCount}`,
            pl: `Pytania ${questionCount}`,
          })}
          tone={BASE_TONE}
        />
      </View>
      <View style={{ flexDirection: 'column', gap: 8 }}>
        <OutlineLink
          href={routes.tests as any}
          hint={copy({
            de: 'Öffnet die Tests.',
            en: 'Opens tests.',
            pl: 'Otwiera testy.',
          })}
          label={copy({
            de: 'Zu den Tests',
            en: 'Go to tests',
            pl: 'Przejdź do testów',
          })}
        />
        <OutlineLink
          href={routes.results as any}
          hint={copy({
            de: 'Öffnet die Ergebnisse.',
            en: 'Opens results.',
            pl: 'Otwiera wyniki.',
          })}
          label={copy({
            de: 'Ergebnisse öffnen',
            en: 'Open results',
            pl: 'Otwórz wyniki',
          })}
        />
        <OutlineLink
          href={routes.plan as any}
          hint={copy({
            de: 'Öffnet den Tagesplan.',
            en: 'Opens the daily plan.',
            pl: 'Otwiera plan dnia.',
          })}
          label={copy({
            de: 'Zum Tagesplan',
            en: 'Go to daily plan',
            pl: 'Przejdź do planu dnia',
          })}
        />
      </View>
    </SectionCard>
  );
}

type CompetitionMissingModeSectionProps = {
  copy: (dict: { de: string; en: string; pl: string }) => string;
  modeToken: string | null;
  onOpenFull: () => void;
};

export function CompetitionMissingModeSection({
  copy,
  modeToken,
  onOpenFull,
}: CompetitionMissingModeSectionProps) {
  return (
    <SectionCard
      title={copy({
        de: 'Wettbewerbskürzel',
        en: 'Competition shortcut',
        pl: 'Skrót konkursu',
      })}
    >
      <Text style={{ color: '#475569', fontSize: 14, lineHeight: 20 }}>
        {copy({
          de: `Der Link zu "${formatModeToken(modeToken)}" passt gerade zu keiner Wettbewerbsrunde.`,
          en: `The shortcut for "${formatModeToken(modeToken)}" does not match any competition round right now.`,
          pl: `Skrót do „${formatModeToken(modeToken)}” nie pasuje teraz do żadnej rundy konkursu.`,
        })}
      </Text>
      <PrimaryButton
        label={copy({
          de: 'Vollen Wettbewerb öffnen',
          en: 'Open full competition',
          pl: 'Otwórz pełny konkurs',
        })}
        onPress={onOpenFull}
        tone={BASE_TONE}
      />
    </SectionCard>
  );
}

type CompetitionModeCardProps = {
  copy: (dict: { de: string; en: string; pl: string }) => string;
  item: {
    mode: KangurMobileCompetitionMode;
    questionCount: number;
    pointTier: string;
  };
  locale: KangurMobileLocale;
  onPress: () => void;
  isStart?: boolean;
};

export function CompetitionModeCard({
  copy,
  item,
  locale,
  onPress,
  isStart = false,
}: CompetitionModeCardProps) {
  return (
    <SectionCard title={formatCompetitionModeTitle(item.mode, locale)}>
      <View style={{ flexDirection: 'row', flexWrap: 'wrap', gap: 8 }}>
        <StatusPill
          label={formatQuestionCount(item.questionCount, locale)}
          tone={SUCCESS_TONE}
        />
        <StatusPill
          label={formatCompetitionTierLabel(item.pointTier, locale)}
          tone={WARNING_TONE}
        />
      </View>
      <Text style={{ color: '#475569', fontSize: 14, lineHeight: 20 }}>
        {formatCompetitionModeDescription(item.mode, locale)}
      </Text>
      <PrimaryButton
        label={isStart ? copy({
          de: 'Runde starten',
          en: 'Start this round',
          pl: 'Uruchom rundę',
        }) : copy({
          de: 'Zurück zur Auswahl',
          en: 'Back to setup',
          pl: 'Wróć do wyboru',
        })}
        onPress={onPress}
        tone={isStart ? undefined : BASE_TONE}
      />
    </SectionCard>
  );
}

import { useLocalSearchParams, useRouter } from 'expo-router';
import { Text, View } from 'react-native';
import { useEffect, useState } from 'react';

import { KangurMobileAiTutorCard } from '../ai-tutor/KangurMobileAiTutorCard';
import { useKangurMobileI18n } from '../i18n/kangurMobileI18n';
import { createKangurLessonsCatalogHref } from '../lessons/lessonHref';
import { createKangurPlanHref } from '../plan/planHref';
import { createKangurPracticeHref } from '../practice/practiceHref';
import { createKangurResultsHref } from '../scores/resultsHref';
import { KangurMobileScrollScreen } from '../shared/KangurMobileUi';
import { createKangurTestsHref } from '../tests/testsHref';
import { KangurMobileCompetitionPlayer } from './competition-player';
import { createKangurCompetitionHref } from './competitionHref';
import {
  BASE_TONE,
  INDIGO_TONE,
  OutlineLink,
  PrimaryButton,
  SectionCard,
  StatusPill,
  SUCCESS_TONE,
  WARNING_TONE,
} from './competition-primitives';
import {
  formatCompetitionModeDescription,
  formatCompetitionModeTitle,
  formatCompetitionTierLabel,
  formatModeToken,
  formatQuestionCount,
} from './competition-utils';
import {
  useKangurMobileCompetition,
  type KangurMobileCompetitionMode,
} from './useKangurMobileCompetition';

const COMPETITION_ROUTE = createKangurCompetitionHref();
const TESTS_ROUTE = createKangurTestsHref();
const LESSONS_ROUTE = createKangurLessonsCatalogHref();
const PRACTICE_ROUTE = createKangurPracticeHref('mixed');
const PLAN_ROUTE = createKangurPlanHref();
const RESULTS_ROUTE = createKangurResultsHref();

export function KangurCompetitionScreen(): React.JSX.Element {
  const params = useLocalSearchParams<{ mode?: string | string[] }>();
  const router = useRouter();
  const { copy, locale } = useKangurMobileI18n();
  const rawModeParam = Array.isArray(params.mode) ? params.mode[0] ?? null : params.mode ?? null;
  const { focusedMode, modeToken, modes } = useKangurMobileCompetition(rawModeParam);
  const [activeMode, setActiveMode] = useState<KangurMobileCompetitionMode | null>(null);

  useEffect(() => {
    if (focusedMode) {
      setActiveMode(focusedMode);
    }
  }, [focusedMode]);

  useEffect(() => {
    if (!activeMode) {
      return;
    }

    const stillExists = modes.some((item) => item.mode === activeMode);
    if (!stillExists) {
      setActiveMode(null);
    }
  }, [activeMode, modes]);

  const activeItem = modes.find((item) => item.mode === activeMode) ?? null;
  const missingFocusedMode =
    modeToken !== null && focusedMode === null && activeItem === null;
  const setupTutorContext = {
    contentId: 'game:kangur:setup',
    focusId: 'kangur-game-kangur-setup',
    focusKind: 'screen' as const,
    surface: 'game' as const,
    title: copy({
      de: 'Kangur-Wettbewerb',
      en: 'Kangaroo competition',
      pl: 'Konkurs Kangur',
    }),
  };

  return (
    <KangurMobileScrollScreen
      backgroundColor='#f8fafc'
      contentContainerStyle={{ gap: 16, padding: 16, paddingBottom: 32 }}
      edges={['top', 'left', 'right']}
      keyboardShouldPersistTaps='handled'
    >
        <SectionCard
          title={copy({
            de: 'Kangur-Wettbewerb',
            en: 'Kangaroo competition',
            pl: 'Konkurs Kangur',
          })}
        >
          <Text style={{ color: '#475569', fontSize: 14, lineHeight: 20 }}>
            {copy({
              de: 'Wähle eine Runde des Wettbewerbs 2024 und löse die Fragen in deinem eigenen Tempo.',
              en: 'Choose a 2024 competition round and solve the tasks at your own pace.',
              pl: 'Wybierz rundę konkursu z 2024 roku i rozwiązuj zadania we własnym tempie.',
            })}
          </Text>
          <View style={{ flexDirection: 'row', flexWrap: 'wrap', gap: 8 }}>
            <StatusPill
              label={copy({
                de: `Runden ${modes.length}`,
                en: `Rounds ${modes.length}`,
                pl: `Rundy ${modes.length}`,
              })}
              tone={INDIGO_TONE}
            />
            <StatusPill
              label={copy({
                de: `Fragen ${modes.reduce((total, mode) => total + mode.questionCount, 0)}`,
                en: `Questions ${modes.reduce((total, mode) => total + mode.questionCount, 0)}`,
                pl: `Pytania ${modes.reduce((total, mode) => total + mode.questionCount, 0)}`,
              })}
              tone={BASE_TONE}
            />
          </View>
          <View style={{ flexDirection: 'column', gap: 8 }}>
            <OutlineLink
              href={TESTS_ROUTE}
              hint={copy({
                de: 'Öffnet die Tests.',
                en: 'Opens tests.',
                pl: 'Otwiera testy.',
              })}
              label={copy({
                de: 'Zu den Tests',
                en: 'Go to tests',
                pl: 'Przejdź do testów',
              })}
            />
            <OutlineLink
              href={RESULTS_ROUTE}
              hint={copy({
                de: 'Öffnet die Ergebnisse.',
                en: 'Opens results.',
                pl: 'Otwiera wyniki.',
              })}
              label={copy({
                de: 'Ergebnisse öffnen',
                en: 'Open results',
                pl: 'Otwórz wyniki',
              })}
            />
            <OutlineLink
              href={PLAN_ROUTE}
              hint={copy({
                de: 'Öffnet den Tagesplan.',
                en: 'Opens the daily plan.',
                pl: 'Otwiera plan dnia.',
              })}
              label={copy({
                de: 'Zum Tagesplan',
                en: 'Go to daily plan',
                pl: 'Przejdź do planu dnia',
              })}
            />
          </View>
        </SectionCard>

        {!activeItem ? (
          <KangurMobileAiTutorCard
            context={setupTutorContext}
            gameTarget='competition'
          />
        ) : null}

        {missingFocusedMode ? (
          <SectionCard
            title={copy({
              de: 'Wettbewerbskürzel',
              en: 'Competition shortcut',
              pl: 'Skrót konkursu',
            })}
          >
            <Text style={{ color: '#475569', fontSize: 14, lineHeight: 20 }}>
              {copy({
                de: `Der Link zu "${formatModeToken(modeToken)}" passt gerade zu keiner Wettbewerbsrunde.`,
                en: `The shortcut for "${formatModeToken(modeToken)}" does not match any competition round right now.`,
                pl: `Skrót do „${formatModeToken(modeToken)}” nie pasuje teraz do żadnej rundy konkursu.`,
              })}
            </Text>
            <PrimaryButton
              label={copy({
                de: 'Vollen Wettbewerb öffnen',
                en: 'Open full competition',
                pl: 'Otwórz pełny konkurs',
              })}
              onPress={() => {
                router.replace(COMPETITION_ROUTE);
              }}
              tone={BASE_TONE}
            />
          </SectionCard>
        ) : null}

        {activeItem ? (
          <>
            <SectionCard title={formatCompetitionModeTitle(activeItem.mode, locale)}>
              <Text style={{ color: '#475569', fontSize: 14, lineHeight: 20 }}>
                {formatCompetitionModeDescription(activeItem.mode, locale)}
              </Text>
              <View style={{ flexDirection: 'row', flexWrap: 'wrap', gap: 8 }}>
                <StatusPill
                  label={formatQuestionCount(activeItem.questionCount, locale)}
                  tone={SUCCESS_TONE}
                />
                <StatusPill
                  label={formatCompetitionTierLabel(activeItem.pointTier, locale)}
                  tone={WARNING_TONE}
                />
              </View>
              <PrimaryButton
                label={copy({
                  de: 'Zurück zur Auswahl',
                  en: 'Back to setup',
                  pl: 'Wróć do wyboru',
                })}
                onPress={() => {
                  setActiveMode(null);
                }}
                tone={BASE_TONE}
              />
            </SectionCard>
            <KangurMobileCompetitionPlayer
              item={activeItem}
              onBackToCatalog={() => {
                setActiveMode(null);
              }}
            />
          </>
        ) : (
          modes.map((item) => (
