    return {
      de: '3-5 Punkte',
      en: '3-5 points',
      pl: '3-5 punktów',
    }[locale];
  }

  return {
    de: `${pointTier} Punkte`,
    en: `${pointTier} points`,
    pl: `${pointTier} punkty`,
  }[locale];
};

export const formatModeToken = (value: string): string =>
  value.replace(/[-_]+/g, ' ').trim();

export const getCompetitionQuestionPointValue = (
  question: Pick<KangurExamQuestion, 'id'>,
): number => {
  if (question.id.includes('_5pt_')) {
    return 5;
  }
  if (question.id.includes('_4pt_')) {
    return 4;
  }
  return 3;
};

export const getCompetitionChoiceDescription = (
  question: KangurExamQuestion,
  index: number,
): string => {
  const describedChoice = question.choiceDescriptions?.[index]?.trim();
  if (describedChoice) {
    return describedChoice;
  }

  const choice = question.choices[index];
  if (typeof choice === 'number') {
    return String(choice);
  }

  return choice ?? '';
};

import type { Href } from 'expo-router';

export const createKangurCompetitionHref = (mode?: string | null): Href => {
  const trimmedMode = mode?.trim();
  if (!trimmedMode) {
    return '/competition' as Href;
  }

  return ({
    pathname: '/competition',
    params: {
      mode: trimmedMode,
    },
  }) as unknown as Href;
};

import {
  getKangurCompetitionQuestions,
  type KangurCompetitionMode,
} from '@kangur/core';
import type { KangurExamQuestion } from '@kangur/contracts/kangur';
import { useMemo } from 'react';

export type KangurMobileCompetitionMode = Exclude<
  KangurCompetitionMode,
  'training_3pt'
>;

export type KangurMobileCompetitionModeItem = {
  mode: KangurMobileCompetitionMode;
  pointTier: '3' | '4' | '5' | 'mixed';
  questionCount: number;
  questions: KangurExamQuestion[];
};

type UseKangurMobileCompetitionResult = {
  focusedMode: KangurMobileCompetitionMode | null;
  modeToken: string | null;
  modes: KangurMobileCompetitionModeItem[];
};

const MODE_ORDER: KangurMobileCompetitionMode[] = [
  'full_test_2024',
  'original_2024',
  'original_4pt_2024',
  'original_5pt_2024',
];

const MODE_POINT_TIERS: Record<KangurMobileCompetitionMode, '3' | '4' | '5' | 'mixed'> = {
  full_test_2024: 'mixed',
  original_2024: '3',
  original_4pt_2024: '4',
  original_5pt_2024: '5',
};

const FOCUS_ALIASES: Record<string, KangurMobileCompetitionMode> = {
  '2024': 'full_test_2024',
  '3': 'original_2024',
  '3pt': 'original_2024',
  '4': 'original_4pt_2024',
  '4pt': 'original_4pt_2024',
  '5': 'original_5pt_2024',
  '5pt': 'original_5pt_2024',
  full: 'full_test_2024',
};

const resolveFocusedMode = (
  modeToken: string,
  items: KangurMobileCompetitionModeItem[],
): KangurMobileCompetitionMode | null => {
  const normalizedToken = modeToken.trim().toLowerCase();
  if (!normalizedToken) {
    return null;
  }

  const aliasedMode = FOCUS_ALIASES[normalizedToken];
  if (aliasedMode) {
    return aliasedMode;
  }

  const byId = items.find((item) => item.mode === normalizedToken);
  if (byId) {
    return byId.mode;
  }

  return null;
};

export const useKangurMobileCompetition = (
  rawModeToken: string | null,
): UseKangurMobileCompetitionResult => {
  const modeToken = rawModeToken?.trim().toLowerCase() || null;

  const modes = useMemo<KangurMobileCompetitionModeItem[]>(
    () =>
      MODE_ORDER.map((mode) => {
        const questions = getKangurCompetitionQuestions(mode);
        return {
          mode,
          pointTier: MODE_POINT_TIERS[mode],
          questionCount: questions.length,
          questions,
        };
      }),
    [],
  );

  return {
    focusedMode:
      modeToken && modes.length > 0 ? resolveFocusedMode(modeToken, modes) : null,
    modeToken,
    modes,
  };
};

export type KangurMobileDeveloperConfigSources = {
  extraDevAutoSignIn?: boolean;
  extraDevLearnerLogin?: string;
  extraDevLearnerPassword?: string;
};

export type KangurMobileDeveloperConfig = {
  autoSignIn: boolean;
  learnerLoginName: string | null;
  learnerPassword: string | null;
};

const normalizeDeveloperConfigValue = (
  value: string | undefined,
): string | null => {
  const trimmed = value?.trim();
  if (!trimmed) {
    return null;
  }

  return trimmed;
};

export const resolveKangurMobileDeveloperConfigFromSources = ({
  extraDevAutoSignIn,
  extraDevLearnerLogin,
  extraDevLearnerPassword,
}: KangurMobileDeveloperConfigSources): KangurMobileDeveloperConfig => ({
  autoSignIn: extraDevAutoSignIn === true,
  learnerLoginName: normalizeDeveloperConfigValue(extraDevLearnerLogin),
  learnerPassword: normalizeDeveloperConfigValue(extraDevLearnerPassword),
});

import {
  resolveKangurMobileAuthMode,
  type KangurMobileAuthMode,
} from '../auth/mobileAuthMode';

export type KangurMobilePublicConfigSources = {
  envApiUrl?: string;
  envAuthMode?: string;
  extraApiUrl?: string;
  extraAuthMode?: string;
};

export type KangurMobilePublicConfig = {
  apiUrl: string | null;
  authMode: KangurMobileAuthMode;
};

export const normalizeKangurMobilePublicApiUrl = (
  value: string | undefined,
): string | null => {
  const trimmed = value?.trim();
  if (!trimmed) {
    return null;
  }

  return trimmed.replace(/\/$/, '');
};

export const resolveKangurMobilePublicConfigFromSources = ({
  envApiUrl,
  envAuthMode,
  extraApiUrl,
  extraAuthMode,
}: KangurMobilePublicConfigSources): KangurMobilePublicConfig => ({
  apiUrl:
    normalizeKangurMobilePublicApiUrl(envApiUrl) ??
    normalizeKangurMobilePublicApiUrl(extraApiUrl),
  authMode: resolveKangurMobileAuthMode(envAuthMode ?? extraAuthMode),
});

