} from './mobileDuelDefaults';

const MOBILE_DUEL_LOBBY_LIMIT = 12;
const MOBILE_DUEL_PRESENCE_LIMIT = 24;
const MOBILE_DUEL_OPPONENT_LIMIT = 6;
