const MOBILE_DUEL_LOBBY_POLL_MS = 15_000;
const MOBILE_DUEL_PRESENCE_POLL_MS = 20_000;

type KangurMobileDuelModeFilter = 'all' | KangurDuelMode;
type KangurMobileDuelSeriesBestOf = 1 | 3 | 5 | 7 | 9;
