export type UseKangurMobileDuelsLobbyResult = {
  actionError: string | null;
  createPrivateChallenge: (
    opponentLearnerId: string,
    overrides?: KangurMobileDuelCreateOverrides,
  ) => Promise<string | null>;
  createPublicChallenge: (
    overrides?: KangurMobileDuelCreateOverrides,
  ) => Promise<string | null>;
  createQuickMatch: (
