  const message = error.message.trim();
  if (!message) {
    return copy({
      de: 'Die Duellstatistiken konnten nicht geladen werden.',
      en: 'Could not load duel stats.',
      pl: 'Nie udało się pobrać statystyk pojedynków.',
    });
