  const duelLeaderboard = useKangurMobileHomeDuelsLeaderboard({
    enabled: true,
  });
  const currentLearnerDuelRank = activeDuelLearnerId
    ? duelLeaderboard.entries.findIndex((entry) => entry.learnerId === activeDuelLearnerId)
