                    <View
                      key={check.label}
                      style={{
                        backgroundColor:
                          check.status === 'ready'
                            ? '#ecfdf5'
                            : check.status === 'info'
                              ? '#eff6ff'
                              : '#fff7ed',
                        borderColor:
                          check.status === 'ready'
                            ? '#a7f3d0'
                            : check.status === 'info'
                              ? '#bfdbfe'
                              : '#fed7aa',
