                      <Text style={{ color: '#0f172a', fontWeight: '700' }}>
                        {check.label}:{' '}
                        {check.status === 'ready'
                          ? copy({
                              de: 'bereit',
                              en: 'ready',
                              pl: 'gotowe',
                            })
                          : check.status === 'info'
                            ? copy({
                                de: 'läuft',
                                en: 'in progress',
                                pl: 'w toku',
                              })
                            : copy({
                                de: 'fehlt',
                                en: 'missing',
                                pl: 'brak',
