                  </Text>
                ) : trainingFocus.error ? (
                  <Text style={{ color: '#b91c1c', lineHeight: 20 }}>
                    {trainingFocus.error}
                  </Text>
                ) : (
                  <View style={{ gap: 12 }}>
                    {trainingFocus.weakestOperation ? (
                      <FocusCard
                        actionHref={createKangurPracticeHref(
                          trainingFocus.weakestOperation.operation,
                        )}
                        actionLabel={copy({
                          de: 'Schwächsten Modus trainieren',
