        />
        {completionLessonAction}
        <LinkButton
          href={createKangurPlanHref()}
          label={translateKangurMobileActionLabel('Open daily plan', locale)}
          tone='secondary'
        />
        <LinkButton
          href={profileHref}
          label={translateKangurMobileActionLabel('Back to profile', locale)}
          tone='brand'
        />
