const KANGUR_PROGRESS_STORAGE_KEY = 'sprycio_progress';
const KANGUR_PROGRESS_OWNER_STORAGE_KEY = 'sprycio_progress_owner';

export const readWebCookieValue = (name: string): string | null => {
  if (typeof document === 'undefined') {
    return null;
  }

  const cookiePrefix = `${name}=`;
  const rawCookie = document.cookie
    .split(';')
    .map((entry) => entry.trim())
    .find((entry) => entry.startsWith(cookiePrefix));

  return rawCookie ? decodeURIComponent(rawCookie.slice(cookiePrefix.length)) : null;
};

export const buildKangurMobileRuntimeHeaders = (
  storage: KangurClientStorageAdapter,
  webCookieToken: string | null
): Headers => {
  const headers = new Headers();
  const activeLearnerId = storage.getItem(KANGUR_MOBILE_ACTIVE_LEARNER_STORAGE_KEY);
  const bearerToken = storage.getItem(KANGUR_MOBILE_AUTH_BEARER_TOKEN_STORAGE_KEY);

  if (activeLearnerId) {
    headers.set(KANGUR_ACTIVE_LEARNER_HEADER, activeLearnerId);
  }
  if (bearerToken) {
    headers.set('Authorization', `Bearer ${bearerToken}`);
  }

  const csrfToken = resolveKangurMobileCsrfRequestToken({
    storage,
    webCookieToken,
  });
  if (csrfToken) {
    headers.set('x-csrf-token', csrfToken);
  }

  return headers;
};

export const createTrackedKangurMobileProgressStore = (
  baseProgressStore: KangurProgressStore,
  storage: KangurClientStorageAdapter
): KangurProgressStore => ({
  ...baseProgressStore,
  saveProgress: (progress) => {
    const normalizedProgress = baseProgressStore.saveProgress(progress);

    persistKangurMobileHomeLessonCheckpoints({
      learnerIdentity: resolveKangurMobileHomeLessonCheckpointIdentity(storage),
      snapshot: buildPersistedKangurMobileHomeLessonCheckpointSnapshot({
        progress: normalizedProgress,
      }),
      storage,
    });

    return normalizedProgress;
  },
});

const createKangurMobileApiBaseUrlState = () =>
  resolveKangurMobileApiBaseUrl({
    configuredApiBaseUrl: resolveKangurMobilePublicConfig().apiUrl ?? null,
    developmentHost: extractExpoDevelopmentHost({
      hostUri: Constants.expoConfig?.hostUri ?? Constants.platform?.hostUri ?? null,
      linkingUri: Constants.linkingUri ?? null,
    }),
    platformOs: Platform.OS,
  });

const createKangurMobileApiClient = (
  apiBaseUrl: string,
  storage: KangurClientStorageAdapter
) =>
  createKangurApiClient({
    baseUrl: apiBaseUrl,
    credentials: 'include',
    fetchImpl: fetch,
    getHeaders: () => buildKangurMobileRuntimeHeaders(storage, readWebCookieValue('csrf-token')),
    onResponse: (response) => {
      persistKangurMobileCsrfTokenFromHeaders(storage, response.headers);
    },
  });

export const createKangurMobileRuntime = (): KangurMobileRuntime => {
  const apiBaseUrlState = createKangurMobileApiBaseUrlState();
  const storage = createMobileDevelopmentKangurStorage();
  const baseProgressStore = createKangurProgressStore({
    storage,
    progressStorageKey: KANGUR_PROGRESS_STORAGE_KEY,
    ownerStorageKey: KANGUR_PROGRESS_OWNER_STORAGE_KEY,
  });

  return {
    ...apiBaseUrlState,
    apiClient: createKangurMobileApiClient(apiBaseUrlState.apiBaseUrl, storage),
    defaultDailyGoalGames: KANGUR_PROFILE_DEFAULT_DAILY_GOAL_GAMES,
    progressStore: createTrackedKangurMobileProgressStore(baseProgressStore, storage),
    storage,
  };
};

import type { PlatformOSType } from 'react-native';

export type KangurApiBaseUrlSource =
  | 'env'
  | 'android-emulator-default'
  | 'localhost-default'
  | 'expo-development-host'
  | 'expo-development-host-default';

type KangurResolvedApiBaseUrl = {
  apiBaseUrl: string;
  apiBaseUrlSource: KangurApiBaseUrlSource;
};

type ResolveKangurMobileApiBaseUrlOptions = {
  configuredApiBaseUrl: string | null;
  developmentHost: string | null;
  platformOs: PlatformOSType;
};

const ANDROID_EMULATOR_HOST = '10.0.2.2';
const LOOPBACK_HOSTS = new Set(['localhost', '127.0.0.1', '::1']);

export const normalizeApiBaseUrl = (value: string | undefined | null): string | null => {
  const trimmed = value?.trim();
  if (!trimmed) {
    return null;
  }

  return trimmed.replace(/\/$/, '');
};

const normalizeHostname = (value: string | null | undefined): string | null => {
  const trimmed = value?.trim().toLowerCase();
  return trimmed ? trimmed : null;
};

const readUrlHostname = (value: string): string | null => {
  try {
    return normalizeHostname(new URL(value).hostname);
  } catch {
    return null;
  }
};

const createApiUrlWithHostname = (
  apiUrl: string,
  hostname: string,
): string | null => {
  try {
    const parsed = new URL(apiUrl);
    parsed.hostname = hostname;
    return parsed.toString().replace(/\/$/, '');
  } catch {
    return null;
  }
};

export const isLoopbackHost = (hostname: string | null): boolean =>
  hostname !== null && LOOPBACK_HOSTS.has(hostname);

const parseRuntimeHostCandidate = (value: string | null | undefined): string | null => {
  const trimmed = value?.trim();
  if (!trimmed) {
    return null;
  }

  const normalizedCandidate = /^[a-z][a-z0-9+.-]*:\/\//i.test(trimmed)
    ? trimmed
    : `http://${trimmed}`;

  try {
    return normalizeHostname(new URL(normalizedCandidate).hostname);
  } catch {
    return null;
  }
};

export const extractExpoDevelopmentHost = ({
  hostUri,
  linkingUri,
}: {
  hostUri?: string | null;
  linkingUri?: string | null;
}): string | null => {
  for (const candidate of [hostUri, linkingUri]) {
    const parsedHost = parseRuntimeHostCandidate(candidate);
    if (parsedHost) {
      return parsedHost;
    }
  }

  return null;
};

const resolveDefaultApiBaseUrl = (
  platformOs: PlatformOSType,
): KangurResolvedApiBaseUrl => {
  if (platformOs === 'android') {
    return {
      apiBaseUrl: 'http://10.0.2.2:3000',
      apiBaseUrlSource: 'android-emulator-default',
    };
  }

  return {
    apiBaseUrl: 'http://localhost:3000',
    apiBaseUrlSource: 'localhost-default',
  };
};

const canUseExpoDevelopmentHost = (
  developmentHost: string | null,
  platformOs: PlatformOSType,
): developmentHost is string =>
  platformOs !== 'web' &&
  developmentHost !== null &&
  !isLoopbackHost(developmentHost) &&
  developmentHost !== ANDROID_EMULATOR_HOST;

export const resolveKangurMobileApiBaseUrl = ({
  configuredApiBaseUrl,
  developmentHost,
  platformOs,
}: ResolveKangurMobileApiBaseUrlOptions): KangurResolvedApiBaseUrl => {
  const normalizedConfiguredApiBaseUrl = normalizeApiBaseUrl(configuredApiBaseUrl);
  const normalizedDevelopmentHost = normalizeHostname(developmentHost);

  if (normalizedConfiguredApiBaseUrl) {
    const configuredHostname = readUrlHostname(normalizedConfiguredApiBaseUrl);

    if (
      canUseExpoDevelopmentHost(normalizedDevelopmentHost, platformOs) &&
      (isLoopbackHost(configuredHostname) || configuredHostname === ANDROID_EMULATOR_HOST)
    ) {
      return {
        apiBaseUrl:
          createApiUrlWithHostname(
            normalizedConfiguredApiBaseUrl,
            normalizedDevelopmentHost,
          ) ?? normalizedConfiguredApiBaseUrl,
        apiBaseUrlSource: 'expo-development-host',
      };
    }

    if (platformOs === 'android' && isLoopbackHost(configuredHostname)) {
      return {
        apiBaseUrl:
          createApiUrlWithHostname(
            normalizedConfiguredApiBaseUrl,
            ANDROID_EMULATOR_HOST,
          ) ?? normalizedConfiguredApiBaseUrl,
        apiBaseUrlSource: 'android-emulator-default',
      };
    }

    return {
      apiBaseUrl: normalizedConfiguredApiBaseUrl,
      apiBaseUrlSource: 'env',
    };
  }

  const defaultApiBaseUrlState = resolveDefaultApiBaseUrl(platformOs);

  if (canUseExpoDevelopmentHost(normalizedDevelopmentHost, platformOs)) {
    return {
      apiBaseUrl:
        createApiUrlWithHostname(
          defaultApiBaseUrlState.apiBaseUrl,
          normalizedDevelopmentHost,
        ) ?? defaultApiBaseUrlState.apiBaseUrl,
      apiBaseUrlSource: 'expo-development-host-default',
    };
  }

  return defaultApiBaseUrlState;
};

