import { getKangurLeaderboardOperationInfo } from '@kangur/core';
import type { KangurScore } from '@kangur/contracts/kangur';

import {
  getKangurMobileLocaleTag,
  type KangurMobileLocale,
  type KangurMobileLocalizedValue,
} from '../i18n/kangurMobileI18n';

export type KangurMobileScoreFamily = 'all' | 'arithmetic' | 'logic' | 'time';
export type KangurMobileScorePracticeFamily = Exclude<
  KangurMobileScoreFamily,
  'all'
>;

export type KangurMobileScoreSummary = {
  arithmeticSessions: number;
  averageAccuracyPercent: number;
  bestAccuracyPercent: number;
  logicSessions: number;
  timeSessions: number;
  totalSessions: number;
};

export type KangurMobileOperationPerformance = {
  averageAccuracyPercent: number;
  bestAccuracyPercent: number;
  family: KangurMobileScorePracticeFamily;
  operation: string;
  sessions: number;
};

export type KangurMobileTrainingFocus = {
  strongestOperation: KangurMobileOperationPerformance | null;
  weakestOperation: KangurMobileOperationPerformance | null;
};

const KANGUR_MOBILE_SCORE_FAMILY_LABELS: Record<
  KangurMobileScorePracticeFamily,
  KangurMobileLocalizedValue<string>
> = {
  arithmetic: {
    de: 'Arithmetiktraining',
    en: 'Arithmetic practice',
    pl: 'Trening arytmetyczny',
  },
  logic: {
    de: 'Logiktraining',
    en: 'Logic practice',
    pl: 'Trening logiczny',
  },
  time: {
    de: 'Zeittraining',
    en: 'Time practice',
    pl: 'Trening czasu',
  },
};

const toSafeRoundedPercent = (value: number): number => {
  if (!Number.isFinite(value)) {
    return 0;
  }

  return Math.max(0, Math.min(100, Math.round(value)));
};

export const getKangurMobileScoreAccuracyPercent = (
  score: Pick<KangurScore, 'correct_answers' | 'total_questions'>,
): number => {
  if (score.total_questions <= 0) {
    return 0;
  }

  return toSafeRoundedPercent(
    (score.correct_answers / score.total_questions) * 100,
  );
};

export const isKangurMobileLogicScore = (
  score: Pick<KangurScore, 'operation'>,
): boolean => score.operation.startsWith('logical_');

export const isKangurMobileTimeScore = (
  score: Pick<KangurScore, 'operation'>,
): boolean => score.operation === 'clock' || score.operation === 'calendar';

export const getKangurMobileScoreFamily = (
  score: Pick<KangurScore, 'operation'>,
): KangurMobileScorePracticeFamily => {
  if (isKangurMobileLogicScore(score)) {
    return 'logic';
  }
  if (isKangurMobileTimeScore(score)) {
    return 'time';
  }
  return 'arithmetic';
};

export const filterKangurMobileScores = (
  scores: KangurScore[],
  filters: {
    family?: KangurMobileScoreFamily;
    operation?: string | null;
  } = {},
): KangurScore[] => {
  const family = filters.family ?? 'all';
  const operation = filters.operation?.trim() ?? '';

  return scores.filter((score) => {
    if (operation && score.operation !== operation) {
      return false;
    }

    if (family === 'logic') {
      return isKangurMobileLogicScore(score);
    }

    if (family === 'time') {
      return isKangurMobileTimeScore(score);
    }

    if (family === 'arithmetic') {
      return getKangurMobileScoreFamily(score) === 'arithmetic';
    }

    return true;
  });
};

export const listKangurMobileScoreOperations = (
  scores: KangurScore[],
): string[] => {
  const seen = new Set<string>();
  const operations: string[] = [];

  scores.forEach((score) => {
    const operation = score.operation.trim();
    if (!operation || seen.has(operation)) {
      return;
    }

    seen.add(operation);
    operations.push(operation);
  });

  return operations;
};

export const buildKangurMobileOperationPerformance = (
  scores: KangurScore[],
): KangurMobileOperationPerformance[] => {
  const byOperation = new Map<
    string,
    {
        bestAccuracyPercent: number;
        family: KangurMobileScorePracticeFamily;
        sessions: number;
        totalAccuracyPercent: number;
      }
  >();

  scores.forEach((score) => {
    const operation = score.operation.trim();
    if (!operation) {
      return;
    }

    const accuracyPercent = getKangurMobileScoreAccuracyPercent(score);
    const current =
      byOperation.get(operation) ?? {
        bestAccuracyPercent: 0,
        family: getKangurMobileScoreFamily(score),
        sessions: 0,
        totalAccuracyPercent: 0,
      };

    current.sessions += 1;
    current.totalAccuracyPercent += accuracyPercent;
    current.bestAccuracyPercent = Math.max(
      current.bestAccuracyPercent,
      accuracyPercent,
    );
    byOperation.set(operation, current);
  });

  return Array.from(byOperation.entries())
    .map(([operation, stats]) => ({
      averageAccuracyPercent: toSafeRoundedPercent(
        stats.totalAccuracyPercent / stats.sessions,
      ),
      bestAccuracyPercent: stats.bestAccuracyPercent,
      family: stats.family,
      operation,
      sessions: stats.sessions,
    }))
    .sort((left, right) => {
      if (right.averageAccuracyPercent !== left.averageAccuracyPercent) {
        return right.averageAccuracyPercent - left.averageAccuracyPercent;
      }
      if (right.sessions !== left.sessions) {
        return right.sessions - left.sessions;
      }
      return left.operation.localeCompare(right.operation);
    });
};

export const buildKangurMobileTrainingFocus = (
  operationPerformance: KangurMobileOperationPerformance[],
): KangurMobileTrainingFocus => ({
  strongestOperation: operationPerformance[0] ?? null,
  weakestOperation:
    operationPerformance.length > 1
      ? operationPerformance[operationPerformance.length - 1] ?? null
      : null,
});

export const buildKangurMobileScoreSummary = (
  scores: KangurScore[],
): KangurMobileScoreSummary => {
  if (scores.length === 0) {
    return {
      arithmeticSessions: 0,
      averageAccuracyPercent: 0,
      bestAccuracyPercent: 0,
      logicSessions: 0,
      timeSessions: 0,
      totalSessions: 0,
    };
  }

  let arithmeticSessions = 0;
  let logicSessions = 0;
  let timeSessions = 0;
  let totalAccuracy = 0;
  let bestAccuracyPercent = 0;

  scores.forEach((score) => {
    const accuracyPercent = getKangurMobileScoreAccuracyPercent(score);
    totalAccuracy += accuracyPercent;
    bestAccuracyPercent = Math.max(bestAccuracyPercent, accuracyPercent);
    const family = getKangurMobileScoreFamily(score);
    if (family === 'logic') {
      logicSessions += 1;
      return;
    }
    if (family === 'time') {
      timeSessions += 1;
      return;
    }
    arithmeticSessions += 1;
  });

  return {
    arithmeticSessions,
    averageAccuracyPercent: toSafeRoundedPercent(totalAccuracy / scores.length),
    bestAccuracyPercent,
    logicSessions,
    timeSessions,
    totalSessions: scores.length,
  };
};

export const formatKangurMobileScoreOperation = (
  value: string,
  locale: KangurMobileLocale = 'pl',
): string => getKangurLeaderboardOperationInfo(value, locale).label;

export const formatKangurMobileScoreFamily = (
  family: KangurMobileScorePracticeFamily,
  locale: KangurMobileLocale = 'pl',
): string => KANGUR_MOBILE_SCORE_FAMILY_LABELS[family][locale];

export const formatKangurMobileScoreDateTime = (
  value: string,
  locale: KangurMobileLocale = 'pl',
): string => {
  const parsed = new Date(value);
  if (Number.isNaN(parsed.getTime())) {
    return value.slice(0, 16);
  }

  return parsed.toLocaleString(getKangurMobileLocaleTag(locale), {
    day: '2-digit',
    hour: '2-digit',
    minute: '2-digit',
    month: 'short',
  });
};

export const formatKangurMobileScoreDuration = (value: number): string => {
  const safeValue = Math.max(0, Math.floor(value));
  if (safeValue < 60) {
    return `${safeValue}s`;
  }

  const minutes = Math.floor(safeValue / 60);
  const seconds = safeValue % 60;
  return `${minutes}m ${seconds.toString().padStart(2, '0')}s`;
};

import { kangurScoreSchema, type KangurScore } from '@kangur/contracts/kangur';
import type { KangurClientStorageAdapter } from '@kangur/platform';

const KANGUR_MOBILE_RECENT_RESULTS_STORAGE_KEY = 'kangur.mobile.scores.recent';
const KANGUR_MOBILE_RECENT_RESULTS_SNAPSHOT_LIMIT = 3;

const parsePersistedRecentResultsStore = (
  rawSnapshot: string | null,
): Record<string, KangurScore[]> => {
  const normalizedRawSnapshot = rawSnapshot?.trim() ?? '';
  if (!normalizedRawSnapshot) {
    return {};
  }

  try {
    const parsedSnapshot = JSON.parse(normalizedRawSnapshot) as unknown;
    if (
      !parsedSnapshot ||
      typeof parsedSnapshot !== 'object' ||
      Array.isArray(parsedSnapshot)
    ) {
      return {};
    }

    return Object.entries(parsedSnapshot).reduce<Record<string, KangurScore[]>>(
      (snapshot, [identityKey, value]) => {
        const parsedResults = kangurScoreSchema
          .array()
          .max(KANGUR_MOBILE_RECENT_RESULTS_SNAPSHOT_LIMIT)
          .safeParse(value);
        if (parsedResults.success) {
          snapshot[identityKey] = parsedResults.data;
        }
        return snapshot;
      },
      {},
    );
  } catch {
    return {};
  }
};

export const resolvePersistedKangurMobileRecentResults = ({
  identityKey,
  limit,
  storage,
}: {
  identityKey: string;
  limit: number;
  storage: KangurClientStorageAdapter;
}): KangurScore[] | null => {
  const store = parsePersistedRecentResultsStore(
    storage.getItem(KANGUR_MOBILE_RECENT_RESULTS_STORAGE_KEY),
  );
  const persistedResults = store[identityKey];
  if (!persistedResults) {
    return null;
  }

  return persistedResults.slice(
    0,
    Math.min(limit, KANGUR_MOBILE_RECENT_RESULTS_SNAPSHOT_LIMIT),
  );
};

export const persistKangurMobileRecentResults = ({
  identityKey,
  results,
  storage,
}: {
  identityKey: string;
  results: KangurScore[];
  storage: KangurClientStorageAdapter;
}): void => {
  const store = parsePersistedRecentResultsStore(
    storage.getItem(KANGUR_MOBILE_RECENT_RESULTS_STORAGE_KEY),
  );

  store[identityKey] = results.slice(
    0,
    KANGUR_MOBILE_RECENT_RESULTS_SNAPSHOT_LIMIT,
  );

  storage.setItem(
    KANGUR_MOBILE_RECENT_RESULTS_STORAGE_KEY,
    JSON.stringify(store),
  );
};

import type { KangurClientStorageAdapter } from '@kangur/platform';

import type {
  KangurMobileOperationPerformance,
  KangurMobileTrainingFocus,
} from './mobileScoreSummary';

const KANGUR_MOBILE_TRAINING_FOCUS_STORAGE_KEY =
  'kangur.mobile.scores.trainingFocus';

const isPersistedOperationPerformance = (
  value: unknown,
): value is KangurMobileOperationPerformance => {
  if (!value || typeof value !== 'object' || Array.isArray(value)) {
    return false;
  }

  const candidate = value as Record<string, unknown>;
  return (
    typeof candidate['operation'] === 'string' &&
    candidate['operation'].trim().length > 0 &&
    (candidate['family'] === 'arithmetic' ||
      candidate['family'] === 'logic' ||
      candidate['family'] === 'time') &&
    typeof candidate['averageAccuracyPercent'] === 'number' &&
    Number.isFinite(candidate['averageAccuracyPercent']) &&
    candidate['averageAccuracyPercent'] >= 0 &&
    candidate['averageAccuracyPercent'] <= 100 &&
    typeof candidate['bestAccuracyPercent'] === 'number' &&
    Number.isFinite(candidate['bestAccuracyPercent']) &&
    candidate['bestAccuracyPercent'] >= 0 &&
    candidate['bestAccuracyPercent'] <= 100 &&
    typeof candidate['sessions'] === 'number' &&
    Number.isInteger(candidate['sessions']) &&
    candidate['sessions'] >= 1
  );
};

const parsePersistedTrainingFocus = (
  value: unknown,
): KangurMobileTrainingFocus | null => {
  if (!value || typeof value !== 'object' || Array.isArray(value)) {
    return null;
  }

  const candidate = value as Record<string, unknown>;
  const strongestOperation =
    candidate['strongestOperation'] === null
      ? null
      : isPersistedOperationPerformance(candidate['strongestOperation'])
        ? candidate['strongestOperation']
        : null;
  const weakestOperation =
    candidate['weakestOperation'] === null
      ? null
      : isPersistedOperationPerformance(candidate['weakestOperation'])
        ? candidate['weakestOperation']
        : null;

  if (
    !('strongestOperation' in candidate) ||
    !('weakestOperation' in candidate)
  ) {
    return null;
  }

  if (
    candidate['strongestOperation'] !== null &&
    !isPersistedOperationPerformance(candidate['strongestOperation'])
  ) {
    return null;
  }

  if (
    candidate['weakestOperation'] !== null &&
    !isPersistedOperationPerformance(candidate['weakestOperation'])
  ) {
    return null;
  }

  return {
    strongestOperation,
    weakestOperation,
  };
};

const parsePersistedTrainingFocusStore = (
  rawSnapshot: string | null,
): Record<string, KangurMobileTrainingFocus> => {
  const normalizedRawSnapshot = rawSnapshot?.trim() ?? '';
  if (!normalizedRawSnapshot) {
    return {};
  }

  try {
    const parsedSnapshot = JSON.parse(normalizedRawSnapshot) as unknown;
    if (
      !parsedSnapshot ||
      typeof parsedSnapshot !== 'object' ||
      Array.isArray(parsedSnapshot)
    ) {
      return {};
    }

    return Object.entries(parsedSnapshot).reduce<Record<string, KangurMobileTrainingFocus>>(
      (snapshot, [identityKey, value]) => {
        const parsedFocus = parsePersistedTrainingFocus(value);
        if (parsedFocus) {
          snapshot[identityKey] = parsedFocus;
        }
        return snapshot;
      },
      {},
    );
  } catch {
    return {};
  }
};

export const resolvePersistedKangurMobileTrainingFocus = ({
  identityKey,
  storage,
}: {
  identityKey: string;
  storage: KangurClientStorageAdapter;
}): KangurMobileTrainingFocus | null => {
  const store = parsePersistedTrainingFocusStore(
    storage.getItem(KANGUR_MOBILE_TRAINING_FOCUS_STORAGE_KEY),
  );
  return store[identityKey] ?? null;
};

export const persistKangurMobileTrainingFocus = ({
  focus,
  identityKey,
  storage,
}: {
  focus: KangurMobileTrainingFocus;
  identityKey: string;
  storage: KangurClientStorageAdapter;
}): void => {
  const store = parsePersistedTrainingFocusStore(
    storage.getItem(KANGUR_MOBILE_TRAINING_FOCUS_STORAGE_KEY),
  );
  store[identityKey] = focus;
  storage.setItem(
    KANGUR_MOBILE_TRAINING_FOCUS_STORAGE_KEY,
    JSON.stringify(store),
  );
};

