): string => formatKangurMobileQuestionCount(count, locale);

export const formatPointsLabel = (
  value: number,
  locale: KangurMobileLocale,
): string =>
  ({
    de: `${value} Pkt`,
    en: `${value} pts`,
    pl: `${value} pkt`,
  })[locale];

export const resolveQuestionStatusTone = (scorePercent: number): Tone => {
  if (scorePercent >= 80) {
    return SUCCESS_TONE;
  }
  if (scorePercent >= 50) {
    return WARNING_TONE;
  }
  return ERROR_TONE;
};

type ChoiceButtonProps = {
  choice: KangurTestChoice;
  disabled?: boolean;
  isCorrect: boolean;
  isRevealed: boolean;
  isSelected: boolean;
  label: string;
  locale: KangurMobileLocale;
  onPress: () => void;
};

export function ChoiceButton(props: ChoiceButtonProps): React.JSX.Element {
  const {
    choice,
    disabled = false,
    isCorrect,
    isRevealed,
    isSelected,
    label,
    locale,
    onPress,
  } = props;
  const tone = isRevealed
    ? isCorrect
      ? SUCCESS_TONE
      : isSelected
        ? ERROR_TONE
        : BASE_TONE
    : isSelected
      ? INDIGO_TONE
      : BASE_TONE;

  return (
    <ChoiceCardButton
      description={choice.description || undefined}
      disabled={disabled}
      helperText={
        choice.svgContent.trim().length > 0 ? (
          <Text
            style={{
              color: '#64748b',
              fontSize: 12,
              lineHeight: 16,
            }}
          >
            {
              {
                de: 'Diese Antwort hat zusatzliche Illustrationen.',
                en: 'This answer includes extra illustration content.',
                pl: 'Ta odpowiedź ma dodatkową ilustrację.',
              }[locale]
            }
          </Text>
        ) : undefined
      }
      indexLabel={label}
      label={choice.text}
      onPress={onPress}
      tone={tone}
    />
  );
}

import type { Href } from 'expo-router';

export const createKangurTestsHref = (focus?: string | null): Href => {
  const trimmedFocus = focus?.trim();
  if (!trimmedFocus) {
    return '/tests' as Href;
  }

  return ({
    pathname: '/tests',
    params: {
      focus: trimmedFocus,
    },
  }) as unknown as Href;
};

import { KANGUR_TEST_QUESTIONS_SETTING_KEY, KANGUR_TEST_SUITES_SETTING_KEY, kangurTestQuestionStoreSchema, kangurTestSuitesSchema, type KangurTestQuestion, type KangurTestQuestionStore, type KangurTestSuite } from '@kangur/contracts/kangur-tests';
import { useQuery } from '@tanstack/react-query';
import { useMemo } from 'react';

import { useKangurMobileI18n } from '../i18n/kangurMobileI18n';
import { useKangurMobileRuntime } from '../providers/KangurRuntimeContext';

type KangurLiteSettingRecord = {
  key: string;
  value: string;
};

export type KangurMobileTestSuiteItem = {
  questionCount: number;
  questions: KangurTestQuestion[];
  suite: KangurTestSuite;
};

type UseKangurMobileTestsResult = {
  error: string | null;
  focusToken: string | null;
  focusedSuiteId: string | null;
  isLoading: boolean;
  refresh: () => Promise<void>;
  suites: KangurMobileTestSuiteItem[];
};

const parseJsonValue = <T,>(
  raw: string | undefined,
  parser: {
    safeParse: (value: unknown) => { success: true; data: T } | { success: false };
  },
  fallback: T,
): T => {
  if (typeof raw !== 'string' || raw.trim().length === 0) {
    return fallback;
  }

  try {
    const parsed = parser.safeParse(JSON.parse(raw));
    return parsed.success ? parsed.data : fallback;
  } catch {
    return fallback;
  }
};

const isLiveSuite = (
  suite: Pick<KangurTestSuite, 'enabled' | 'publicationStatus'>,
): boolean => suite.enabled && suite.publicationStatus === 'live';

const isPublishedQuestion = (
  question: Pick<KangurTestQuestion, 'editorial'>,
): boolean => question.editorial.workflowStatus === 'published';

const getPublishedQuestionsForSuite = (
  questionStore: KangurTestQuestionStore,
  suiteId: string,
): KangurTestQuestion[] =>
  Object.values(questionStore)
    .filter(
      (question) => question.suiteId === suiteId && isPublishedQuestion(question),
    )
    .sort((left, right) => {
      const orderDelta = left.sortOrder - right.sortOrder;
      if (orderDelta !== 0) {
        return orderDelta;
      }

      return left.id.localeCompare(right.id);
    });

const resolveFocusedSuiteId = (
  focusToken: string,
  suites: KangurMobileTestSuiteItem[],
): string | null => {
  const normalized = focusToken.trim().toLowerCase();
  if (!normalized) {
    return null;
  }

  const byId = suites.find((entry) => entry.suite.id.toLowerCase() === normalized);
  if (byId) {
    return byId.suite.id;
  }

  const byTitle = suites.find((entry) =>
    entry.suite.title.toLowerCase().includes(normalized),
  );
  if (byTitle) {
    return byTitle.suite.id;
  }

  const byCategory = suites.find((entry) =>
    entry.suite.category.toLowerCase().includes(normalized),
  );
  if (byCategory) {
    return byCategory.suite.id;
  }

  const byYear = suites.find(
    (entry) =>
      typeof entry.suite.year === 'number' &&
      String(entry.suite.year) === normalized,
  );
  if (byYear) {
    return byYear.suite.id;
  }

  return null;
};

export const useKangurMobileTests = (
  rawFocusToken: string | null,
): UseKangurMobileTestsResult => {
  const { apiBaseUrl } = useKangurMobileRuntime();
  const { copy } = useKangurMobileI18n();
  const focusToken = rawFocusToken?.trim().toLowerCase() || null;

  const settingsQuery = useQuery({
    queryKey: ['kangur-mobile', 'tests', 'lite-settings', apiBaseUrl],
    queryFn: async (): Promise<KangurLiteSettingRecord[]> => {
      const response = await fetch(`${apiBaseUrl}/api/settings/lite`, {
        cache: 'no-store',
        credentials: 'include',
      });

      if (!response.ok) {
        throw new Error(`Failed to fetch lite settings (${response.status})`);
      }

      const payload = await response.json();
      if (!Array.isArray(payload)) {
        return [];
      }

      return payload.filter(
        (entry): entry is KangurLiteSettingRecord =>
          typeof entry === 'object' &&
          entry !== null &&
          typeof entry['key'] === 'string' &&
          typeof entry['value'] === 'string',
      );
    },
    staleTime: 30_000,
  });

  const suites = useMemo(() => {
    const settingsByKey = new Map(
      (settingsQuery.data ?? []).map((entry) => [entry.key, entry.value]),
    );
    const parsedSuites = parseJsonValue(
      settingsByKey.get(KANGUR_TEST_SUITES_SETTING_KEY),
      kangurTestSuitesSchema,
      [],
    )
      .filter(isLiveSuite)
      .sort((left, right) => {
        const orderDelta = left.sortOrder - right.sortOrder;
        if (orderDelta !== 0) {
          return orderDelta;
        }

        return left.id.localeCompare(right.id);
      });
    const questionStore = parseJsonValue(
      settingsByKey.get(KANGUR_TEST_QUESTIONS_SETTING_KEY),
      kangurTestQuestionStoreSchema,
      {},
    );

    return parsedSuites.map((suite) => {
      const questions = getPublishedQuestionsForSuite(questionStore, suite.id);
      return {
        questionCount: questions.length,
        questions,
        suite,
      };
    });
  }, [settingsQuery.data]);

  return {
    error:
      settingsQuery.error instanceof Error
        ? copy({
            de: 'Die Tests konnten nicht geladen werden.',
            en: 'Could not load the tests.',
            pl: 'Nie udało się pobrać testów.',
          })
        : null,
    focusToken,
    focusedSuiteId:
      focusToken && suites.length > 0
        ? resolveFocusedSuiteId(focusToken, suites)
        : null,
    isLoading: settingsQuery.isLoading,
    refresh: async () => {
      await settingsQuery.refetch();
    },
    suites,
  };
};

import { Suspense } from 'react';

import KangurLoadingFallback from '../components/KangurLoadingFallback';
import { StudiqQueryProvider } from '../providers/QueryProvider';
import { DEFAULT_SITE_I18N_CONFIG } from '@/shared/contracts/site-i18n';
import { getLiteSettingsForHydration } from '@/shared/lib/lite-settings-ssr';

import type { Metadata } from 'next';
import type { JSX, ReactNode } from 'react';

import './globals.css';
import './kangur/kangur.css';

export const metadata: Metadata = {
  title: 'StudiQ',
};

export default async function RootLayout({
  children,
}: {
  children: ReactNode;
}): Promise<JSX.Element> {
  const liteSettings = await getLiteSettingsForHydration();
  const sanitizedLiteSettingsScript =
    liteSettings.length > 0
      ? `self.__LITE_SETTINGS__=${JSON.stringify(liteSettings).replace(/</g, '\\u003c')}`
      : null;

  return (
    <html
      lang={DEFAULT_SITE_I18N_CONFIG.defaultLocale}
      className='kangur-surface-active'
      suppressHydrationWarning
    >
      <body className='kangur-surface-active'>
        {sanitizedLiteSettingsScript ? (
          <script
            dangerouslySetInnerHTML={{
              __html: sanitizedLiteSettingsScript,
            }}
          />
        ) : null}
        <Suspense fallback={<KangurLoadingFallback />}>
          <StudiqQueryProvider>
            <main id='kangur-main-content'>{children}</main>
          </StudiqQueryProvider>
        </Suspense>
      </body>
    </html>
  );
}

'use client';

import { QueryClient, QueryClientProvider } from '@tanstack/react-query';
import { useState } from 'react';

import { QUERY_KEYS } from '@/shared/lib/query-keys';

import type { ReactNode } from 'react';

let browserQueryClient: QueryClient | null = null;
type WindowLiteSettingsHydration = typeof globalThis & { __LITE_SETTINGS__?: unknown[] };

const hydrateLiteSettingsQueryCache = (queryClient: QueryClient): void => {
  if (typeof globalThis === 'undefined') {
    return;
  }

  const initialSettings = (globalThis as WindowLiteSettingsHydration).__LITE_SETTINGS__;
  if (!Array.isArray(initialSettings) || initialSettings.length === 0) {
    return;
  }

  const queryKey = QUERY_KEYS.settings.scope('lite');
  if (!queryClient.getQueryData(queryKey)) {
    queryClient.setQueryData(queryKey, initialSettings);
  }
};

const getQueryClient = (): QueryClient => {
  if (typeof window === 'undefined') {
    return new QueryClient();
  }
  if (!browserQueryClient) {
    browserQueryClient = new QueryClient();
    hydrateLiteSettingsQueryCache(browserQueryClient);
  }
  return browserQueryClient;
};

export function StudiqQueryProvider({ children }: { children: ReactNode }): ReactNode {
  const [queryClient] = useState(getQueryClient);

  return (
    <QueryClientProvider client={queryClient}>
      {children}
    </QueryClientProvider>
  );
}
